import re
from llama_index.core.schema import AgentOutput

class SafeAgentOutputParser:
    PII_PATTERNS = [
        r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b',
        r'\b\d{3}[-.]?\d{3}[-.]?\d{4}\b'
    ]

    @staticmethod
    def parse(agent_output: AgentOutput) -> AgentOutput:
        response_text = str(agent_output)
        for pattern in SafeAgentOutputParser.PII_PATTERNS:
            if re.search(pattern, response_text):
                return AgentOutput(
                    response="[REDACTED: PII detected in response]",
                    source_nodes=agent_output.source_nodes
                )
        return agent_output

